const Footer = ({ data }) => {
  return (
    <footer id="contact" className="kaki-halaman">
      <h2 className="judul-kaki-halaman">Let's Collaborate</h2>
      <p className="teks-kaki-halaman">
        I am open to professional discussions and new opportunities in information technology.
      </p>
      <div className="tautan-sosial">
        <a href={`mailto:${data.email}`} className="tombol primer">Send Email</a>
        <a href={data.linkedin} target="_blank" rel="noreferrer" className="tombol">Visit LinkedIn</a>
      </div>
      <p className="hak-cipta">
        &copy; {new Date().getFullYear()} {data.name}. All rights reserved.
      </p>
    </footer>
  );
};

export default Footer;
